var input = inputs.Length > 0 ? inputs[0] : null;
        if (input is null)
            return PixelBuffer.CreateSolid(context.TileSize, context.TileSize, 0, 0, 0);

        var brightness = GetFloat(parameters, "brightness", 0f);
        var contrast = GetFloat(parameters, "contrast", 0f);
        var saturation = GetFloat(parameters, "saturation", 0f);
        var hueShift = GetFloat(parameters, "hueShift", 0f);
        var gamma = GetFloat(parameters, "gamma", 1f);
        var colorTemp = GetFloat(parameters, "colorTemp", 0f);
        var tintColor = GetColor(parameters, "tintColor", System.Windows.Media.Color.FromRgb(255,255,255));
        // Convert color picker into per-channel multipliers in 0..2 range (keeping default white -> 1.0 multiplier)
        var tintR = tintColor.R / 255f * 2f;
        var tintG = tintColor.G / 255f * 2f;
        var tintB = tintColor.B / 255f * 2f;
        var shadowClip = GetFloat(parameters, "shadowClip", 0f);
        var highlightClip = GetFloat(parameters, "highlightClip", 1f);
        var paletteSteps = GetInt(parameters, "paletteSteps", 0);
        var invert = GetBool(parameters, "invert");

        var result = input.Clone();

        result.Apply((r, g, b, a) =>
        {
            if (invert)
            {
                r = 1f - r;
                g = 1f - g;
                b = 1f - b;
            }

            // Brightness
            r += brightness;
            g += brightness;
            b += brightness;

            // Contrast (around midpoint 0.5)
            var contrastFactor = 1f + contrast;
            r = (r - 0.5f) * contrastFactor + 0.5f;
            g = (g - 0.5f) * contrastFactor + 0.5f;
            b = (b - 0.5f) * contrastFactor + 0.5f;

            // Gamma correction
            if (MathF.Abs(gamma - 1f) > 0.01f)
            {
                var invGamma = 1f / MathF.Max(0.1f, gamma);
                r = MathF.Pow(Math.Clamp(r, 0f, 1f), invGamma);
                g = MathF.Pow(Math.Clamp(g, 0f, 1f), invGamma);
                b = MathF.Pow(Math.Clamp(b, 0f, 1f), invGamma);
            }

            // Saturation (adjust toward luminance)
            var lum = 0.2126f * r + 0.7152f * g + 0.0722f * b;
            var satFactor = 1f + saturation;
            r = lum + (r - lum) * satFactor;
            g = lum + (g - lum) * satFactor;
            b = lum + (b - lum) * satFactor;

            // Color temperature: warm shifts toward red/yellow, cool toward blue
            if (MathF.Abs(colorTemp) > 0.01f)
            {
                r += colorTemp * 0.1f;
                g += colorTemp * 0.02f;
                b -= colorTemp * 0.1f;
            }

            // RGB tint multiplier
            r *= tintR;
            g *= tintG;
            b *= tintB;

            // Hue shift (convert to HSV, shift, convert back)
            if (MathF.Abs(hueShift) > 0.5f)
            {
                RgbToHsv(r, g, b, out var h, out var s, out var v);
                h = (h + hueShift / 360f) % 1f;
                if (h < 0f) h += 1f;
                HsvToRgb(h, s, v, out r, out g, out b);
            }

            // Levels: shadow/highlight clip
            if (shadowClip > 0f || highlightClip < 1f)
            {
                var range = MathF.Max(0.001f, highlightClip - shadowClip);
                r = (r - shadowClip) / range;
                g = (g - shadowClip) / range;
                b = (b - shadowClip) / range;
            }

            // Palette limiting (posterize/indexed color mode)
            if (paletteSteps > 1)
            {
                var steps = paletteSteps - 1f;
                r = MathF.Round(r * steps) / steps;
                g = MathF.Round(g * steps) / steps;
                b = MathF.Round(b * steps) / steps;
            }

            r = Math.Clamp(r, 0f, 1f);
            g = Math.Clamp(g, 0f, 1f);
            b = Math.Clamp(b, 0f, 1f);
            return (r, g, b, a);
        });

        return result;

    private static void RgbToHsv(float r, float g, float b, out float h, out float s, out float v)
    {
        var max = MathF.Max(r, MathF.Max(g, b));
        var min = MathF.Min(r, MathF.Min(g, b));
        var delta = max - min;

        v = max;
        s = max > 0.0001f ? delta / max : 0f;

        if (delta < 0.0001f)
        {
            h = 0f;
        }
        else if (MathF.Abs(max - r) < 0.0001f)
        {
            h = ((g - b) / delta) / 6f;
        }
        else if (MathF.Abs(max - g) < 0.0001f)
        {
            h = (2f + (b - r) / delta) / 6f;
        }
        else
        {
            h = (4f + (r - g) / delta) / 6f;
        }

        if (h < 0f) h += 1f;
    }

    private static void HsvToRgb(float h, float s, float v, out float r, out float g, out float b)
    {
        var i = (int)(h * 6f);
        var f = h * 6f - i;
        var p = v * (1f - s);
        var q = v * (1f - f * s);
        var t = v * (1f - (1f - f) * s);

        switch (i % 6)
        {
            case 0: r = v; g = t; b = p; break;
            case 1: r = q; g = v; b = p; break;
            case 2: r = p; g = v; b = t; break;
            case 3: r = p; g = q; b = v; break;
            case 4: r = t; g = p; b = v; break;
            default: r = v; g = p; b = q; break;
        }
    }
}
